(()=>{let n=self;n.addEventListener("push",i=>{if(!i.data)return;let{title:t,body:e}=i.data.json();i.waitUntil(n.registration.showNotification(t,{body:e,icon:"/icons/icon-192.png",badge:"/icons/icon-192.png",vibrate:[200,100,200]}))}),n.addEventListener("notificationclick",i=>{i.notification.close(),i.waitUntil(n.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>i.length>0?i[0].focus():n.clients.openWindow("/")))})})();